import { HEADERS } from "../constants.js";
import type {
  StellarPaymentPayload,
  StellarPaymentRequirements,
} from "../types.js";
import { safeDecodeHeader } from "../utils.js";

// ── Parse incoming payment header ─────────────────────────────────────────────

/**
 * Extract and decode the X-PAYMENT header from a Request.
 * Returns null if the header is missing or malformed.
 */
export function parsePaymentHeader(
  request: Request,
): StellarPaymentPayload | null {
  const header = request.headers.get(HEADERS.X_PAYMENT);
  if (!header) return null;
  return safeDecodeHeader<StellarPaymentPayload>(header);
}

// ── Structural validation ─────────────────────────────────────────────────────

export interface ValidationResult {
  isValid: boolean;
  reason?: string;
}

/**
 * Perform lightweight structural validation of a payment payload before
 * sending it to the facilitator. Catches obvious malformed payloads early.
 */
export function validatePaymentPayload(
  payload: StellarPaymentPayload,
  requirements: StellarPaymentRequirements,
): ValidationResult {
  if (payload.x402Version !== 1) {
    return { isValid: false, reason: "Unsupported x402Version" };
  }

  if (payload.scheme !== "exact") {
    return { isValid: false, reason: `Unsupported scheme: ${payload.scheme}` };
  }

  if (payload.network !== requirements.network) {
    return {
      isValid: false,
      reason: `Network mismatch: expected ${requirements.network}, got ${payload.network}`,
    };
  }

  if (
    !payload.payload?.transaction ||
    typeof payload.payload.transaction !== "string"
  ) {
    return { isValid: false, reason: "Missing or invalid transaction XDR" };
  }

  return { isValid: true };
}
