import {
  OPENZEPPELIN_FACILITATOR_URLS,
} from "./constants.js";
import type {
  FacilitatorSettleResponse,
  FacilitatorVerifyResponse,
  StellarNetworkAlias,
  StellarPaymentPayload,
  StellarPaymentRequirements,
} from "./types.js";

// ── Facilitator client ───────────────────────────────────────────────────────

/**
 * Verify a payment payload against requirements via the facilitator.
 * Does NOT submit the transaction on-chain.
 */
export async function verifyPayment(
  facilitatorUrl: string,
  payload: StellarPaymentPayload,
  requirements: StellarPaymentRequirements,
): Promise<FacilitatorVerifyResponse> {
  const res = await fetch(`${facilitatorUrl}/verify`, {
    method: "POST",
    headers: { "Content-Type": "application/json" },
    body: JSON.stringify({
      paymentPayload: payload,
      paymentRequirements: requirements,
    }),
  });

  if (!res.ok) {
    const text = await res.text().catch(() => res.statusText);
    return { isValid: false, invalidReason: `Facilitator error ${res.status}: ${text}` };
  }

  return (await res.json()) as FacilitatorVerifyResponse;
}

/**
 * Settle a payment via the facilitator.
 * Verifies the payload and submits the transaction on-chain.
 */
export async function settlePayment(
  facilitatorUrl: string,
  payload: StellarPaymentPayload,
  requirements: StellarPaymentRequirements,
): Promise<FacilitatorSettleResponse> {
  const res = await fetch(`${facilitatorUrl}/settle`, {
    method: "POST",
    headers: { "Content-Type": "application/json" },
    body: JSON.stringify({
      paymentPayload: payload,
      paymentRequirements: requirements,
    }),
  });

  if (!res.ok) {
    const text = await res.text().catch(() => res.statusText);
    return {
      success: false,
      errorReason: `Facilitator error ${res.status}: ${text}`,
    };
  }

  return (await res.json()) as FacilitatorSettleResponse;
}

/**
 * Returns the default OpenZeppelin facilitator URL for the given network.
 */
export function getDefaultFacilitatorUrl(network: StellarNetworkAlias): string {
  return OPENZEPPELIN_FACILITATOR_URLS[network];
}
