import { getDefaultFacilitatorUrl, settlePayment, verifyPayment } from "../facilitator.js";
import { CAIP2_NETWORKS, HEADERS, X402_VERSION } from "../constants.js";
import type {
  StellarPaymentRequired,
  StellarPaymentResponse,
  X402StellarConfig,
} from "../types.js";
import { decodeHeader, encodeHeader, safeDecodeHeader } from "../utils.js";
import {
  buildPaymentRequired,
  buildPaymentRequirements,
} from "./payment-required.js";
import { parsePaymentHeader, validatePaymentPayload } from "./verify.js";
import type { StellarPaymentPayload } from "../types.js";

// ── Types ────────────────────────────────────────────────────────────────────

type NextRouteHandler = (
  request: Request,
  context?: { params?: Record<string, string | string[]> },
) => Response | Promise<Response>;

// ── withX402 — route handler wrapper ─────────────────────────────────────────

/**
 * Wrap a Next.js App Router route handler with x402 payment gating.
 *
 * @example
 * ```ts
 * // app/api/premium/route.ts
 * import { withX402 } from 'x402-stellar';
 *
 * export const GET = withX402(
 *   async (req) => Response.json({ data: 'premium content' }),
 *   {
 *     amount: '0.01',
 *     asset: 'USDC',
 *     network: 'testnet',
 *     payTo: 'G...',
 *     description: 'Premium API access',
 *   }
 * );
 * ```
 */
export function withX402(
  handler: NextRouteHandler,
  config: X402StellarConfig,
): NextRouteHandler {
  return async (
    request: Request,
    context?: { params?: Record<string, string | string[]> },
  ): Promise<Response> => {
    const resourceUrl = request.url;
    const facilitatorUrl =
      config.facilitatorUrl ?? getDefaultFacilitatorUrl(config.network);

    // Build the payment requirements once
    const requirements = buildPaymentRequirements(config, resourceUrl);

    // ── Step 1: Check for X-PAYMENT header ───────────────────────────────────
    const paymentPayload = parsePaymentHeader(request);

    if (!paymentPayload) {
      // No payment presented — return 402
      return payment402Response(config, resourceUrl);
    }

    // ── Step 2: Structural validation ────────────────────────────────────────
    const structuralCheck = validatePaymentPayload(paymentPayload, requirements);
    if (!structuralCheck.isValid) {
      return payment402Response(config, resourceUrl, structuralCheck.reason);
    }

    // ── Step 3: Verify via facilitator ────────────────────────────────────────
    const verifyResult = await verifyPayment(
      facilitatorUrl,
      paymentPayload,
      requirements,
    ).catch((err: unknown) => ({
      isValid: false,
      invalidReason: `Facilitator verify failed: ${String(err)}`,
    }));

    if (!verifyResult.isValid) {
      return payment402Response(config, resourceUrl, verifyResult.invalidReason);
    }

    // ── Step 4: Settle via facilitator ────────────────────────────────────────
    const settleResult = await settlePayment(
      facilitatorUrl,
      paymentPayload,
      requirements,
    ).catch((err: unknown) => ({
      success: false,
      errorReason: `Facilitator settle failed: ${String(err)}`,
    }));

    if (!settleResult.success) {
      return new Response(
        JSON.stringify({ error: settleResult.errorReason ?? "Settlement failed" }),
        {
          status: 402,
          headers: {
            "Content-Type": "application/json",
            [HEADERS.PAYMENT_REQUIRED]: encodeHeader(
              buildPaymentRequired(config, resourceUrl),
            ),
          },
        },
      );
    }

    // ── Step 5: Call the original handler ─────────────────────────────────────
    const handlerResponse = await handler(request, context);

    // ── Step 6: Attach X-PAYMENT-RESPONSE header ──────────────────────────────
    const paymentResponse: StellarPaymentResponse = {
      success: true,
      txHash: "txHash" in settleResult ? settleResult.txHash : undefined,
      network: CAIP2_NETWORKS[config.network],
    };

    const responseHeaders = new Headers(handlerResponse.headers);
    responseHeaders.set(
      HEADERS.X_PAYMENT_RESPONSE,
      encodeHeader(paymentResponse),
    );

    return new Response(handlerResponse.body, {
      status: handlerResponse.status,
      statusText: handlerResponse.statusText,
      headers: responseHeaders,
    });
  };
}

// ── createX402Middleware — Next.js middleware.ts helper ───────────────────────

export interface X402RouteConfig extends X402StellarConfig {
  /** URL path pattern, e.g. "/api/premium" or "/api/data/:id" */
  path: string;
}

/**
 * Create a Next.js middleware handler that enforces x402 payments on
 * matching routes. Use this in your `middleware.ts` file.
 *
 * @example
 * ```ts
 * // middleware.ts
 * import { createX402Middleware } from 'x402-stellar';
 *
 * export const middleware = createX402Middleware([
 *   {
 *     path: '/api/premium',
 *     amount: '0.01',
 *     asset: 'USDC',
 *     network: 'testnet',
 *     payTo: 'G...',
 *   },
 * ]);
 *
 * export const config = {
 *   matcher: ['/api/premium/:path*'],
 * };
 * ```
 */
export function createX402Middleware(
  routes: X402RouteConfig[],
): (request: Request) => Response | Promise<Response> {
  return async (request: Request): Promise<Response> => {
    const url = new URL(request.url);

    // Find matching route config
    const routeConfig = routes.find((r) => matchPath(r.path, url.pathname));

    if (!routeConfig) {
      // No matching route — pass through (return a next() equivalent)
      return new Response(null, { status: 200, headers: { "x-middleware-next": "1" } });
    }

    const resourceUrl = request.url;
    const facilitatorUrl =
      routeConfig.facilitatorUrl ?? getDefaultFacilitatorUrl(routeConfig.network);
    const requirements = buildPaymentRequirements(routeConfig, resourceUrl);

    const paymentPayload = parsePaymentHeader(request);

    if (!paymentPayload) {
      return payment402Response(routeConfig, resourceUrl);
    }

    const structuralCheck = validatePaymentPayload(paymentPayload, requirements);
    if (!structuralCheck.isValid) {
      return payment402Response(routeConfig, resourceUrl, structuralCheck.reason);
    }

    const verifyResult = await verifyPayment(
      facilitatorUrl,
      paymentPayload,
      requirements,
    ).catch((err: unknown) => ({
      isValid: false,
      invalidReason: `Facilitator verify failed: ${String(err)}`,
    }));

    if (!verifyResult.isValid) {
      return payment402Response(routeConfig, resourceUrl, verifyResult.invalidReason);
    }

    // Payment verified — add a header so the downstream route knows settlement happened
    return new Response(null, {
      status: 200,
      headers: {
        "x-middleware-next": "1",
        "x-x402-payment-verified": "1",
        "x-x402-payload": encodeHeader(paymentPayload),
      },
    });
  };
}

// ── Helpers ──────────────────────────────────────────────────────────────────

function payment402Response(
  config: X402StellarConfig,
  resourceUrl: string,
  error?: string,
): Response {
  const paymentRequired: StellarPaymentRequired = {
    ...buildPaymentRequired(config, resourceUrl),
    ...(error ? { error } : {}),
  };

  return new Response(
    JSON.stringify({ error: error ?? "Payment required", x402: true }),
    {
      status: 402,
      headers: {
        "Content-Type": "application/json",
        [HEADERS.PAYMENT_REQUIRED]: encodeHeader(paymentRequired),
      },
    },
  );
}

/** Simple path matching — supports exact paths and trailing wildcards */
function matchPath(pattern: string, pathname: string): boolean {
  if (pattern.endsWith("*")) {
    return pathname.startsWith(pattern.slice(0, -1));
  }
  return pathname === pattern || pathname.startsWith(`${pattern}/`);
}
