import {
  ASSET_METADATA,
  CAIP2_NETWORKS,
  USDC_CONTRACT_IDS,
  X402_VERSION,
} from "../constants.js";
import type {
  StellarNetworkAlias,
  StellarPaymentRequired,
  StellarPaymentRequirements,
  X402StellarConfig,
} from "../types.js";
import { toBaseUnits } from "../utils.js";

// ── Build PAYMENT-REQUIRED payload ───────────────────────────────────────────

/**
 * Build the PaymentRequired object that is base64-encoded into the
 * `PAYMENT-REQUIRED` response header on a 402.
 */
export function buildPaymentRequired(
  config: X402StellarConfig,
  resourceUrl: string,
): StellarPaymentRequired {
  const requirements = buildPaymentRequirements(config, resourceUrl);
  return {
    x402Version: X402_VERSION,
    accepts: [requirements],
  };
}

/**
 * Build a single StellarPaymentRequirements entry from a route config.
 */
export function buildPaymentRequirements(
  config: X402StellarConfig,
  resourceUrl: string,
): StellarPaymentRequirements {
  const {
    asset,
    amount,
    network,
    payTo,
    description,
    mimeType = "application/json",
    maxTimeoutSeconds = 300,
  } = config;

  const caip2Network = CAIP2_NETWORKS[network];
  const assetMeta = ASSET_METADATA[asset];
  const maxAmountRequired = toBaseUnits(amount, asset);

  // Resolve on-chain asset identifier
  const onChainAsset =
    asset === "XLM" ? "native" : USDC_CONTRACT_IDS[network as StellarNetworkAlias];

  return {
    scheme: "exact",
    network: caip2Network,
    asset: onChainAsset,
    maxAmountRequired,
    payTo,
    resource: resourceUrl,
    description,
    mimeType,
    maxTimeoutSeconds,
    extra: {
      name: assetMeta.name,
      symbol: assetMeta.symbol,
      decimals: assetMeta.decimals,
    },
  };
}
